input.command:
kubectl -n ray patch deployment ray-head --type=strategic -p '{
  "spec": {
    "template": {
      "spec": {
        "containers": [{
          "name": "ray-head",
          "command": ["sh", "-c", "ray start --head --node-ip-address=\"${MY_POD_IP}\" --port=6379 --include-dashboard=true --dashboard-port=8265 --num-cpus=0 --block\n"],
          "ports": [
            {"containerPort": 6379, "name": "gcs"},
            {"containerPort": 8265, "name": "dashboard"}
          ]
        }]
      }
    }
  }
}'
